PRAGMA foreign_keys = ON;

CREATE TABLE IF NOT EXISTS emmiwood_shops (id TEXT PRIMARY KEY, name TEXT NOT NULL, address TEXT NOT NULL, phone TEXT NOT NULL, timezone TEXT NOT NULL, min_notice_minutes INTEGER NOT NULL DEFAULT 240, horizon_days INTEGER NOT NULL DEFAULT 30, change_cutoff_minutes INTEGER NOT NULL DEFAULT 720, created_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS emmiwood_admins (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), email TEXT NOT NULL COLLATE NOCASE, role TEXT NOT NULL CHECK(role IN ('owner','manager','staff','kup_support')), active INTEGER NOT NULL DEFAULT 1, created_at INTEGER NOT NULL DEFAULT (unixepoch()), UNIQUE(shop_id,email));
CREATE TABLE IF NOT EXISTS emmiwood_login_challenges (id TEXT PRIMARY KEY, admin_id TEXT NOT NULL REFERENCES emmiwood_admins(id), code_hash TEXT NOT NULL, expires_at INTEGER NOT NULL, consumed_at INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS emmiwood_sessions (id TEXT PRIMARY KEY, admin_id TEXT NOT NULL REFERENCES emmiwood_admins(id), token_hash TEXT NOT NULL UNIQUE, expires_at INTEGER NOT NULL, revoked_at INTEGER, created_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS emmiwood_barbers (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), name TEXT NOT NULL, bio TEXT NOT NULL DEFAULT '', active INTEGER NOT NULL DEFAULT 1, sort_order INTEGER NOT NULL DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS emmiwood_services (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), name TEXT NOT NULL, description TEXT NOT NULL DEFAULT '', price_cents INTEGER NOT NULL CHECK(price_cents >= 0), duration_minutes INTEGER NOT NULL CHECK(duration_minutes > 0 AND duration_minutes % 5 = 0), buffer_minutes INTEGER NOT NULL DEFAULT 0 CHECK(buffer_minutes >= 0 AND buffer_minutes % 5 = 0), active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)), sort_order INTEGER NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS emmiwood_barber_services (barber_id TEXT NOT NULL REFERENCES emmiwood_barbers(id), service_id TEXT NOT NULL REFERENCES emmiwood_services(id), PRIMARY KEY(barber_id,service_id));
CREATE TABLE IF NOT EXISTS emmiwood_availability (id TEXT PRIMARY KEY, barber_id TEXT NOT NULL REFERENCES emmiwood_barbers(id), weekday INTEGER NOT NULL CHECK(weekday BETWEEN 0 AND 6), start_minute INTEGER NOT NULL CHECK(start_minute >= 0 AND start_minute < 1440), end_minute INTEGER NOT NULL CHECK(end_minute > start_minute AND end_minute <= 1440), active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)));
CREATE TABLE IF NOT EXISTS emmiwood_exceptions (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), barber_id TEXT REFERENCES emmiwood_barbers(id), date TEXT NOT NULL, start_minute INTEGER NOT NULL DEFAULT 0 CHECK(start_minute >= 0 AND start_minute < 1440), end_minute INTEGER NOT NULL DEFAULT 1440 CHECK(end_minute > start_minute AND end_minute <= 1440), kind TEXT NOT NULL CHECK(kind IN ('closed','blocked','available')), note TEXT NOT NULL DEFAULT '', created_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS emmiwood_customers (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), name TEXT NOT NULL, phone TEXT NOT NULL, email TEXT, sms_consent INTEGER NOT NULL DEFAULT 0, booking_restricted INTEGER NOT NULL DEFAULT 0, created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS emmiwood_appointments (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), barber_id TEXT NOT NULL REFERENCES emmiwood_barbers(id), service_id TEXT NOT NULL REFERENCES emmiwood_services(id), customer_id TEXT NOT NULL REFERENCES emmiwood_customers(id), start_at INTEGER NOT NULL, end_at INTEGER NOT NULL, claim_end_at INTEGER NOT NULL, status TEXT NOT NULL CHECK(status IN ('booked','cancelled','completed','no_show','rescheduled')), manage_token_hash TEXT NOT NULL UNIQUE, notes TEXT NOT NULL DEFAULT '', rescheduled_from TEXT REFERENCES emmiwood_appointments(id), created_by_admin_id TEXT REFERENCES emmiwood_admins(id), created_at INTEGER NOT NULL DEFAULT (unixepoch()), updated_at INTEGER NOT NULL DEFAULT (unixepoch()), cancelled_at INTEGER);
CREATE INDEX IF NOT EXISTS idx_emmiwood_appointments_schedule ON emmiwood_appointments(barber_id,start_at,status);
CREATE TABLE IF NOT EXISTS emmiwood_time_claims (appointment_id TEXT NOT NULL REFERENCES emmiwood_appointments(id) ON DELETE CASCADE, barber_id TEXT NOT NULL REFERENCES emmiwood_barbers(id), bucket_start INTEGER NOT NULL, PRIMARY KEY(barber_id,bucket_start));
CREATE INDEX IF NOT EXISTS idx_emmiwood_time_claims_appointment ON emmiwood_time_claims(appointment_id);
CREATE TABLE IF NOT EXISTS emmiwood_events (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), appointment_id TEXT REFERENCES emmiwood_appointments(id), admin_id TEXT REFERENCES emmiwood_admins(id), event_type TEXT NOT NULL, detail_json TEXT NOT NULL DEFAULT '{}', created_at INTEGER NOT NULL DEFAULT (unixepoch()));
CREATE TABLE IF NOT EXISTS emmiwood_notification_outbox (id TEXT PRIMARY KEY, shop_id TEXT NOT NULL REFERENCES emmiwood_shops(id), appointment_id TEXT REFERENCES emmiwood_appointments(id), channel TEXT NOT NULL CHECK(channel IN ('sms','email')), template TEXT NOT NULL, recipient TEXT NOT NULL, payload_json TEXT NOT NULL, provider TEXT NOT NULL DEFAULT 'mock', status TEXT NOT NULL DEFAULT 'queued', available_at INTEGER NOT NULL DEFAULT (unixepoch()), sent_at INTEGER, error TEXT, created_at INTEGER NOT NULL DEFAULT (unixepoch()));

